// WF_PPS_CALIBRATE — scope projects, skip if <20 samples. Runs AFTER WF_REVENUE_ATTRIBUTION.
// Triggers:
//   - Schedule (1st of month 05:00 UTC): all active projects
//   - Webhook POST /webhook/pps/calibrate: { project_id?, force? }
// Pure math — no Claude. Global fetch + $env.

const raw = $input.first().json;
const viaWebhook = !!raw.body;
const payload = raw.body || {};
const projectIdFilter = payload.project_id || null;
const force = payload.force === true;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

let projUrl = `${supabaseUrl}/rest/v1/projects?select=id&or=(status.is.null,status.not.in.(paused,archived))`;
if (projectIdFilter) projUrl = `${supabaseUrl}/rest/v1/projects?id=eq.${projectIdFilter}&select=id`;

const pRes = await fetch(projUrl, { method: 'GET', headers: sbHeaders });
if (!pRes.ok) throw new Error(`Fetch projects failed: HTTP ${pRes.status}: ${await pRes.text()}`);
const projects = await pRes.json();

if (!projects || projects.length === 0) {
  return [{
    json: {
      skipped: true,
      reason: 'No projects to calibrate',
      via_webhook: viaWebhook,
      http_status: 200
    }
  }];
}

return projects.map(p => ({
  json: {
    project_id: p.id,
    force,
    via_webhook: viaWebhook,
    started_at: new Date().toISOString()
  }
}));

// Per-project multivariate regression on pps_calibration samples.
// Features (6): [outlier, seo, script_quality, niche_health, thumbnail_ctr, title_ctr] normalized 0-100.
// Target: implied_actual_score 0-100.
// Method: gradient descent 1000 iterations w/ learning rate 1e-5 (tuned for 0-100 scale) + L2 regularization λ=0.5.
// Prefers GD over normal equations for numerical stability + simpler fallback.
// Final weights clamped [0.05, 0.50] then normalized so sum=1.0 (matches pps_config CHECK).

const data = $input.item.json;
if (data.skipped) return $input.item;

const projectId = data.project_id;
const runStart = Date.now();

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

async function sbGet(url, label) {
  const res = await fetch(url, { method: 'GET', headers: sbHeaders });
  if (!res.ok) throw new Error(`${label} HTTP ${res.status}: ${(await res.text()).slice(0, 200)}`);
  return res.json();
}

const MIN_SAMPLES = 20;
const LAMBDA = 0.5;        // L2 regularization strength
const ITERATIONS = 1000;
const LR = 1e-5;           // learning rate tuned for features in 0-100 scale
const MIN_WEIGHT = 0.05;
const MAX_WEIGHT = 0.50;

try {
  // 1. Load calibration rows with actuals
  const calRows = await sbGet(
    `${supabaseUrl}/rest/v1/pps_calibration?project_id=eq.${projectId}&actual_views_30d=not.is.null&variance_pct=not.is.null&select=id,predicted_pps,pps_breakdown,implied_actual_score,variance_pct&limit=500`,
    'fetch pps_calibration'
  );

  if (!calRows || calRows.length < MIN_SAMPLES) {
    try {
      await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
        method: 'POST',
        headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify({
          project_id: projectId,
          topic_id: null,
          stage: 'pps_calibrate',
          scene_number: null,
          action: 'insufficient_samples',
          status: 'skipped',
          duration_ms: Date.now() - runStart,
          cost_usd: 0,
          retry_count: 0
        })
      });
    } catch (_) { }
    return {
      json: {
        project_id: projectId,
        skipped: true,
        reason: `Only ${calRows ? calRows.length : 0} samples; need >=${MIN_SAMPLES}`,
        sample_size: calRows ? calRows.length : 0,
        via_webhook: data.via_webhook
      }
    };
  }

  // 2. Extract training matrix X (n×6) and target y (n)
  const featKeys = ['outlier', 'seo', 'script_quality', 'niche_health', 'thumbnail_ctr', 'title_ctr'];
  const X = [];
  const y = [];
  let skippedMalformed = 0;
  for (const row of calRows) {
    const bd = row.pps_breakdown || {};
    const features = featKeys.map(k => {
      const f = bd[k];
      if (f && typeof f.normalized === 'number') return f.normalized;
      return null;
    });
    if (features.some(v => v === null)) { skippedMalformed += 1; continue; }
    const target = Number(row.implied_actual_score);
    if (!isFinite(target)) { skippedMalformed += 1; continue; }
    X.push(features);
    y.push(target);
  }

  if (X.length < MIN_SAMPLES) {
    return {
      json: {
        project_id: projectId,
        skipped: true,
        reason: `After filtering malformed breakdowns (${skippedMalformed}), only ${X.length} usable samples`,
        sample_size: X.length,
        via_webhook: data.via_webhook
      }
    };
  }

  const n = X.length;
  const p = 6;

  // 3. Load current weights (for comparison + fallback)
  const cfgArr = await sbGet(
    `${supabaseUrl}/rest/v1/pps_config?project_id=eq.${projectId}&select=id,outlier_weight,seo_weight,script_quality_weight,niche_health_weight,thumbnail_ctr_weight,title_ctr_weight,calibration_sample_count&limit=1`,
    'fetch pps_config'
  );
  let cfg = cfgArr && cfgArr[0] ? cfgArr[0] : null;
  const priorWeights = cfg ? [
    Number(cfg.outlier_weight) || 0.30,
    Number(cfg.seo_weight) || 0.20,
    Number(cfg.script_quality_weight) || 0.20,
    Number(cfg.niche_health_weight) || 0.15,
    Number(cfg.thumbnail_ctr_weight) || 0.10,
    Number(cfg.title_ctr_weight) || 0.05
  ] : [0.30, 0.20, 0.20, 0.15, 0.10, 0.05];

  // 4. Gradient descent with L2 regularization
  // Model: y_hat = X·w where w initialized to priorWeights scaled up to 0-100 contribution scale
  // Because features are 0-100 and y is 0-100, and y_hat = sum(w_i * x_i), and if x_i ≈ y_i, w sums to 1.0.
  // So we keep w on the weight scale (sum≈1) and iterate.
  let w = priorWeights.slice();
  let finalRss = Infinity;
  let converged = false;

  for (let iter = 0; iter < ITERATIONS; iter++) {
    // Gradient = (2/n) * X^T · (X·w - y) + 2·λ·w
    const grad = new Array(p).fill(0);
    let rss = 0;
    for (let i = 0; i < n; i++) {
      let pred = 0;
      for (let j = 0; j < p; j++) pred += X[i][j] * w[j];
      const err = pred - y[i];
      rss += err * err;
      for (let j = 0; j < p; j++) grad[j] += (2 / n) * err * X[i][j];
    }
    for (let j = 0; j < p; j++) grad[j] += 2 * LAMBDA * w[j];

    // Check for divergence (NaN/Infinity)
    let bad = false;
    for (let j = 0; j < p; j++) { if (!isFinite(grad[j]) || !isFinite(w[j])) { bad = true; break; } }
    if (bad) { w = priorWeights.slice(); converged = false; break; }

    // Update
    for (let j = 0; j < p; j++) w[j] -= LR * grad[j];
    finalRss = rss;
    // Early stop if gradient tiny
    const gradMag = Math.sqrt(grad.reduce((s, g) => s + g * g, 0));
    if (gradMag < 1e-4) { converged = true; break; }
  }

  // Sanity check: all finite
  if (!w.every(isFinite)) w = priorWeights.slice();

  // 5. Clamp to [MIN_WEIGHT, MAX_WEIGHT]
  let clamped = w.map(v => Math.max(MIN_WEIGHT, Math.min(MAX_WEIGHT, v)));

  // 6. Normalize sum=1.0 exactly (scale)
  let sum = clamped.reduce((s, v) => s + v, 0);
  if (sum <= 0 || !isFinite(sum)) clamped = priorWeights.slice();
  else clamped = clamped.map(v => v / sum);

  // After normalization, verify floors — a factor might dip below MIN_WEIGHT after scaling.
  // If so, pin it to MIN_WEIGHT and redistribute the remainder proportionally across the rest.
  let needsRedistrib = clamped.some(v => v < MIN_WEIGHT - 1e-9) || clamped.some(v => v > MAX_WEIGHT + 1e-9);
  let redistributeIterations = 0;
  while (needsRedistrib && redistributeIterations < 10) {
    redistributeIterations += 1;
    const fixedIdx = [];
    let fixedSum = 0;
    for (let j = 0; j < p; j++) {
      if (clamped[j] < MIN_WEIGHT) { clamped[j] = MIN_WEIGHT; fixedIdx.push(j); }
      else if (clamped[j] > MAX_WEIGHT) { clamped[j] = MAX_WEIGHT; fixedIdx.push(j); }
    }
    fixedSum = fixedIdx.reduce((s, j) => s + clamped[j], 0);
    const remainingBudget = 1.0 - fixedSum;
    const freeIdx = [];
    for (let j = 0; j < p; j++) if (!fixedIdx.includes(j)) freeIdx.push(j);
    if (freeIdx.length === 0) break;
    const freeSum = freeIdx.reduce((s, j) => s + clamped[j], 0);
    if (freeSum <= 0) {
      const each = remainingBudget / freeIdx.length;
      for (const j of freeIdx) clamped[j] = each;
    } else {
      const scale = remainingBudget / freeSum;
      for (const j of freeIdx) clamped[j] = clamped[j] * scale;
    }
    // Re-check
    needsRedistrib = clamped.some(v => v < MIN_WEIGHT - 1e-9) || clamped.some(v => v > MAX_WEIGHT + 1e-9);
  }

  // Final safety: if still violates, fall back to priors
  if (clamped.some(v => v < MIN_WEIGHT - 1e-9 || v > MAX_WEIGHT + 1e-9)) {
    clamped = priorWeights.slice();
  }

  // 7. Compute R^2 + mean-abs-diff vs prior
  const yMean = y.reduce((s, v) => s + v, 0) / n;
  let ssTot = 0, ssRes = 0;
  for (let i = 0; i < n; i++) {
    let pred = 0;
    for (let j = 0; j < p; j++) pred += X[i][j] * clamped[j];
    // Scale pred back to 0-100: since w sums to 1 and x in 0-100, pred is already 0-100
    ssRes += (y[i] - pred) * (y[i] - pred);
    ssTot += (y[i] - yMean) * (y[i] - yMean);
  }
  const r2 = ssTot > 0 ? Math.max(-1, Math.min(1, 1 - ssRes / ssTot)) : 0;

  const weightsDiff = clamped.map((v, i) => Math.abs(v - priorWeights[i]));
  const maxChangeAbs = Math.max(...weightsDiff);
  const meanChangeAbs = weightsDiff.reduce((s, v) => s + v, 0) / p;
  const weightsChangedPct = Math.round(meanChangeAbs * 10000) / 100; // percentage points (mean abs)

  // 8. Build patch
  const patch = {
    outlier_weight: Math.round(clamped[0] * 10000) / 10000,
    seo_weight: Math.round(clamped[1] * 10000) / 10000,
    script_quality_weight: Math.round(clamped[2] * 10000) / 10000,
    niche_health_weight: Math.round(clamped[3] * 10000) / 10000,
    thumbnail_ctr_weight: Math.round(clamped[4] * 10000) / 10000,
    title_ctr_weight: Math.round(clamped[5] * 10000) / 10000
  };
  // Re-normalize after 4-decimal rounding so CHECK (sum=1.0 ± 0.001) passes
  const rsum = patch.outlier_weight + patch.seo_weight + patch.script_quality_weight + patch.niche_health_weight + patch.thumbnail_ctr_weight + patch.title_ctr_weight;
  if (Math.abs(rsum - 1.0) > 0.0005) {
    // Adjust largest factor to absorb rounding drift
    const keys = ['outlier_weight', 'seo_weight', 'script_quality_weight', 'niche_health_weight', 'thumbnail_ctr_weight', 'title_ctr_weight'];
    let largestKey = keys[0];
    for (const k of keys) if (patch[k] > patch[largestKey]) largestKey = k;
    patch[largestKey] = Math.round((patch[largestKey] + (1.0 - rsum)) * 10000) / 10000;
  }

  const newSampleCount = (cfg?.calibration_sample_count || 0) + n;
  patch.calibration_sample_count = newSampleCount;
  patch.last_calibrated_at = new Date().toISOString();
  patch.calibration_notes = `samples=${n}, r2=${Math.round(r2 * 1000) / 1000}, max_change=${Math.round(maxChangeAbs * 10000) / 100}pp, mean_change=${weightsChangedPct}pp, converged=${converged}, iters=${ITERATIONS}, lambda=${LAMBDA}`;

  // 9. PATCH pps_config (or INSERT if missing)
  let patchStatus = 'ok';
  try {
    if (cfg && cfg.id) {
      const pRes = await fetch(`${supabaseUrl}/rest/v1/pps_config?id=eq.${cfg.id}`, {
        method: 'PATCH',
        headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify(patch)
      });
      if (!pRes.ok) patchStatus = `PATCH HTTP ${pRes.status}: ${(await pRes.text()).slice(0, 200)}`;
    } else {
      const iRes = await fetch(`${supabaseUrl}/rest/v1/pps_config`, {
        method: 'POST',
        headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify({ project_id: projectId, ...patch })
      });
      if (!iRes.ok) patchStatus = `INSERT HTTP ${iRes.status}: ${(await iRes.text()).slice(0, 200)}`;
    }
  } catch (e) { patchStatus = `patch threw: ${e.message}`; }

  // 10. production_logs
  try {
    await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        project_id: projectId,
        topic_id: null,
        stage: 'pps_calibrate',
        scene_number: null,
        action: 'regression',
        status: patchStatus === 'ok' ? 'success' : 'partial',
        duration_ms: Date.now() - runStart,
        cost_usd: 0,
        retry_count: 0
      })
    });
  } catch (_) { }

  return {
    json: {
      project_id: projectId,
      sample_size: n,
      skipped_malformed: skippedMalformed,
      prior_weights: priorWeights,
      new_weights: [
        patch.outlier_weight,
        patch.seo_weight,
        patch.script_quality_weight,
        patch.niche_health_weight,
        patch.thumbnail_ctr_weight,
        patch.title_ctr_weight
      ],
      weights_changed_pct: weightsChangedPct,
      max_change_pp: Math.round(maxChangeAbs * 10000) / 100,
      r2,
      converged,
      calibration_sample_count: newSampleCount,
      patch_status: patchStatus,
      duration_ms: Date.now() - runStart,
      via_webhook: data.via_webhook
    }
  };
} catch (e) {
  try {
    await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        project_id: projectId,
        topic_id: null,
        stage: 'pps_calibrate',
        scene_number: null,
        action: 'regression',
        status: 'error',
        duration_ms: Date.now() - runStart,
        cost_usd: 0,
        retry_count: 0
      })
    });
  } catch (_) { }
  return {
    json: {
      project_id: projectId,
      error: e.message,
      via_webhook: data.via_webhook
    }
  };
}

// Aggregate across projects.
const items = $input.all().map(i => i.json);
const meaningful = items.filter(j => !j.skipped && !j.error);
const skipped = items.filter(j => j.skipped);
const errors = items.filter(j => j.error);

if (meaningful.length === 0) {
  return [{
    json: {
      success: true,
      projects_calibrated: 0,
      projects_skipped: skipped.length,
      projects_errored: errors.length,
      message: skipped[0]?.reason || errors[0]?.error || 'Nothing to calibrate',
      http_status: 200,
      via_webhook: items[0]?.via_webhook || false
    }
  }];
}

return [{
  json: {
    success: true,
    projects_calibrated: meaningful.length,
    projects_skipped: skipped.length,
    projects_errored: errors.length,
    total_samples_used: meaningful.reduce((s, m) => s + (m.sample_size || 0), 0),
    avg_r2: Math.round((meaningful.reduce((s, m) => s + (m.r2 || 0), 0) / meaningful.length) * 1000) / 1000,
    avg_weights_change_pct: Math.round((meaningful.reduce((s, m) => s + (m.weights_changed_pct || 0), 0) / meaningful.length) * 100) / 100,
    per_project: meaningful.map(m => ({
      project_id: m.project_id,
      sample_size: m.sample_size,
      r2: m.r2,
      weights_changed_pct: m.weights_changed_pct,
      max_change_pp: m.max_change_pp,
      converged: m.converged,
      prior_weights: m.prior_weights,
      new_weights: m.new_weights,
      patch_status: m.patch_status
    })),
    skipped_projects: skipped.map(s => ({ project_id: s.project_id, reason: s.reason, sample_size: s.sample_size })),
    errored_projects: errors.map(e => ({ project_id: e.project_id, error: e.error })),
    finished_at: new Date().toISOString(),
    http_status: 200,
    via_webhook: meaningful.some(m => m.via_webhook)
  }
}];
